import React, { useState } from 'react';
import { View, Button, TextInput, Text } from 'react-native';

const App = () => {
  const [code, setCode] = useState('');
  const [token, setToken] = useState('');

  const handleLogin = async () => {
    try {
      const response = await fetch('https://your-auth-server.com/token', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: `grant_type=authorization_code&code=${code}&client_id=mobile_app_client_123&client_secret=secret_abc123xyz456`,
      });

      const data = await response.json();
      setToken(data.access_token);
    } catch (error) {
      console.error('Error exchanging code for token:', error);
    }
  };

  return (
    <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
      <TextInput
        placeholder="Enter Authorization Code"
        value={code}
        onChangeText={setCode}
        style={{ borderWidth: 1, padding: 10, marginBottom: 20 }}
      />
      <Button title="Login" onPress={handleLogin} />
      {token && <Text>Access Token: {token}</Text>}
    </View>
  );
};

export default App;